from typing import TypedDict
from langgraph.graph import StateGraph, END

class RouterState(TypedDict):
    query: str
    route: str
    confidence: float
    response: str

def router_node(state: RouterState) -> RouterState:
    decision = router_chain.invoke({"query": state["query"]})
    route = decision.route if decision.confidence >= 0.6 else "escalate"
    return {**state, "route": route, "confidence": decision.confidence}

def technical_node(state: RouterState) -> RouterState:
    response = technical_chain.invoke({"query": state["query"]})
    return {**state, "response": response}

def billing_node(state: RouterState) -> RouterState:
    response = billing_chain.invoke({"query": state["query"]})
    return {**state, "response": response}

def account_node(state: RouterState) -> RouterState:
    response = account_chain.invoke({"query": state["query"]})
    return {**state, "response": response}

def escalate_node(state: RouterState) -> RouterState:
    response = escalation_chain.invoke({"query": state["query"]})
    return {**state, "response": response}

def dispatch(state: RouterState) -> str:
    return state["route"]  # "technical" | "billing" | "account" | "escalate"

graph = StateGraph(RouterState)
graph.add_node("router",    router_node)
graph.add_node("technical", technical_node)
graph.add_node("billing",   billing_node)
graph.add_node("account",   account_node)
graph.add_node("escalate",  escalate_node)

graph.set_entry_point("router")
graph.add_conditional_edges("router", dispatch, {
    "technical": "technical",
    "billing":   "billing",
    "account":   "account",
    "escalate":  "escalate",
})
for node in ["technical", "billing", "account", "escalate"]:
    graph.add_edge(node, END)

app = graph.compile()
result = app.invoke({"query": "I can't log into my account", "route": "", "confidence": 0.0, "response": ""})
print(result["route"], result["response"][:80])
